#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int safe_strtol(const char *s, int base, long *out) {
    char *endptr;
    long val = strtol(s, &endptr, base);
    if (endptr == s) return 0;  /* No conversion */
    *out = val;
    return 1;  /* Success */
}

int main(void) {
    {
        long val;
        int res = safe_strtol("12345", 10, &val);
        printf("%d\n", (int)(res));
        printf("%d\n", (int)(val));
    }
    {
        long val;
        int res = safe_strtol("0xFF", 16, &val);
        printf("%d\n", (int)(res));
        printf("%d\n", (int)(val));
    }
    {
        long val;
        int res = safe_strtol("42abc", 10, &val);
        printf("%d\n", (int)(res));
        printf("%d\n", (int)(val));
    }
    {
        long val = 999;
        int res = safe_strtol("hello", 10, &val);
        printf("%d\n", (int)(res));
        printf("%d\n", (int)(val));
    }
    return 0;
}

